func (t *tocTransformer) renderHeadingNode(w *bytes.Buffer, source []byte, n ast.Node) (err error) {
	l := w.Len()
	defer func() {
		if r := recover(); r != nil {
			if isGoldmarkIndexOutOfRangePanic(r) {
				w.Truncate(l)
				return
			}
			panic(r)
		}
	}()

	return t.r.Render(w, source, n)
}

func isGoldmarkIndexOutOfRangePanic(r any) bool {
	err, ok := r.(runtime.Error)
	return ok && strings.Contains(err.Error(), "index out of range")
}

type tocPassthroughRenderer struct{}

func (r tocPassthroughRenderer) RegisterFuncs(reg renderer.NodeRendererFuncRegisterer) {
	reg.Register(passthroughAst.KindPassthroughBlock, r.renderPassthrough)
	reg.Register(passthroughAst.KindPassthroughInline, r.renderPassthrough)
}

func (r tocPassthroughRenderer) renderPassthrough(w util.BufWriter, source []byte, n ast.Node, entering bool) (ast.WalkStatus, error) {
	if !entering {
		return ast.WalkContinue, nil
	}

	switch n := n.(type) {
	case *passthroughAst.PassthroughInline:
		_, _ = w.Write(n.Text(source))
	case *passthroughAst.PassthroughBlock:
		for i := 0; i < n.Lines().Len(); i++ {
			_, _ = w.Write(n.Lines().At(i).Value(source))
		}
	}

	return ast.WalkContinue, nil
}

